SELECT faq_seq ,audience ,category ,question ,answer ,sort_seq ,use_yn ,rgst_date_time FROM event.faq
AND audience = #{audience}
AND category = #{category}
AND use_yn = 'Y'
ORDER BY audience, sort_seq, faq_seq

mapper.update:
UPDATE event.faq
SET  audience       = #{audience}
    ,category       = #{category}
    ,question       = #{question}
    ,answer         = #{answer}
    ,sort_seq       = #{sortSeq}
    ,use_yn         = #{useYn}
    ,upt_user_seq   = #{uptUserSeq}
    ,upt_date_time  = CURRENT_TIMESTAMP
WHERE faq_seq = #{faqSeq}
